import React, { useEffect, useRef } from 'react';
import './WeatherMap.css';

const WeatherMap = ({ weather, loading, theme }) => {
  const mapRef = useRef(null);
  const mapInstanceRef = useRef(null);
  const markerRef = useRef(null);

  useEffect(() => {
    // Dynamically load Leaflet to avoid SSR issues
    const initMap = async () => {
      if (!weather?.lat || !weather?.lon) return;

      const L = window.L;
      if (!L) return;

      const lat = weather.lat;
      const lon = weather.lon;

      if (!mapInstanceRef.current) {
        mapInstanceRef.current = L.map(mapRef.current, {
          center: [lat, lon],
          zoom: 10,
          zoomControl: true,
          attributionControl: false,
        });

        const tileUrl = theme === 'dark'
          ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png'
          : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';

        L.tileLayer(tileUrl, { maxZoom: 19 }).addTo(mapInstanceRef.current);
      } else {
        mapInstanceRef.current.setView([lat, lon], 10);

        // Update tile layer for theme
        mapInstanceRef.current.eachLayer(layer => {
          if (layer._url) mapInstanceRef.current.removeLayer(layer);
        });

        const tileUrl = theme === 'dark'
          ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png'
          : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';

        window.L.tileLayer(tileUrl, { maxZoom: 19 }).addTo(mapInstanceRef.current);
      }

      if (markerRef.current) {
        markerRef.current.remove();
      }

      const icon = L.divIcon({
        className: '',
        html: `<div class="map-marker-pin">
          <div class="map-marker-dot">
            <span style="font-size:16px">${getEmoji(weather.weatherCode)}</span>
          </div>
          <div class="map-marker-label">${weather.name}</div>
        </div>`,
        iconSize: [60, 60],
        iconAnchor: [30, 60],
      });

      markerRef.current = L.marker([lat, lon], { icon }).addTo(mapInstanceRef.current);
    };

    // Small delay to ensure map container is rendered
    const timer = setTimeout(initMap, 100);
    return () => clearTimeout(timer);
  }, [weather, theme]);

  const getEmoji = (code) => {
    if (code >= 200 && code < 300) return '⛈️';
    if (code >= 500 && code < 600) return '🌧️';
    if (code >= 600 && code < 700) return '❄️';
    if (code === 800) return '☀️';
    if (code === 801 || code === 802) return '🌤️';
    return '⛅';
  };

  if (loading) return (
    <div className="card map-card">
      <div className="card-title">📍 Location Map</div>
      <div className="skeleton map-skeleton" />
    </div>
  );

  if (!weather) return null;

  return (
    <div className="card map-card">
      <div className="card-title">📍 Location Map</div>
      <div className="map-container" ref={mapRef} />
    </div>
  );
};

export default WeatherMap;
